INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4ba1dde9-3a3c-4472-af05-215a5ccd715d', $q$Declarative YAML workflows$q$, $q$Flows are defined as code in YAML, with a synchronized UI editor, avoiding vendor lock-in to a single scripting language.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4ba1dde9-3a3c-4472-af05-215a5ccd715d', $q$Event-driven triggers$q$, $q$Workflows can start from webhooks, queues, file arrivals or API calls in addition to cron-based scheduling.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4ba1dde9-3a3c-4472-af05-215a5ccd715d', $q$1,200+ plugins$q$, $q$Native integrations for cloud providers, databases, dbt, Kubernetes, containers and general scripting languages.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4ba1dde9-3a3c-4472-af05-215a5ccd715d', $q$Polyglot task execution$q$, $q$A single flow can orchestrate tasks written in different languages and runtimes rather than being Python-only.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4ba1dde9-3a3c-4472-af05-215a5ccd715d', $q$Multi-tenancy and RBAC$q$, $q$Enterprise Edition supports SSO, LDAP/SCIM, and fine-grained role-based access control for large organizations.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4ba1dde9-3a3c-4472-af05-215a5ccd715d', $q$AI Copilot$q$, $q$Enterprise-tier assistant for building, debugging and optimizing workflows, with support for custom models.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4ba1dde9-3a3c-4472-af05-215a5ccd715d', $q$Air-gapped and multi-cloud deployment$q$, $q$Can be self-hosted on-premises, in private cloud, or in air-gapped environments for regulated industries.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4ba1dde9-3a3c-4472-af05-215a5ccd715d', $q$Audit logs and storage isolation$q$, $q$Enterprise governance features for compliance-sensitive teams running orchestration at scale.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4ba1dde9-3a3c-4472-af05-215a5ccd715d', $q$Free, fully-featured open-source self-hosted option with unlimited flows and executions$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4ba1dde9-3a3c-4472-af05-215a5ccd715d', $q$Language-agnostic declarative YAML model avoids Python lock-in$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4ba1dde9-3a3c-4472-af05-215a5ccd715d', $q$Large plugin catalog (1,200+) covering most common data and cloud tools$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4ba1dde9-3a3c-4472-af05-215a5ccd715d', $q$Native event-driven triggers alongside traditional scheduling$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4ba1dde9-3a3c-4472-af05-215a5ccd715d', $q$Strong recent funding and growing enterprise adoption suggest active development$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4ba1dde9-3a3c-4472-af05-215a5ccd715d', $q$Enterprise and Cloud pricing are not published and require contacting sales$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4ba1dde9-3a3c-4472-af05-215a5ccd715d', $q$Younger project than Airflow, so ecosystem maturity and community size are smaller$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4ba1dde9-3a3c-4472-af05-215a5ccd715d', $q$YAML-based flows can become verbose for very complex pipelines$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4ba1dde9-3a3c-4472-af05-215a5ccd715d', $q$Enterprise features (SSO, RBAC, audit logs) are gated behind paid tiers$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4ba1dde9-3a3c-4472-af05-215a5ccd715d', $q$Newer entrant means fewer long-term production case studies compared to Airflow$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4ba1dde9-3a3c-4472-af05-215a5ccd715d', $q$Is Kestra free to use?$q$, $q$Yes, Kestra's open-source edition is free to self-host with unlimited flows and executions and the full plugin library. Paid Cloud and Enterprise tiers add managed hosting, governance and enterprise support.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4ba1dde9-3a3c-4472-af05-215a5ccd715d', $q$How is Kestra different from Apache Airflow?$q$, $q$Kestra uses declarative YAML rather than Python DAGs, supports native event-driven triggers, and lets a single flow mix tasks written in different languages, whereas Airflow is Python-first and primarily schedule-driven.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4ba1dde9-3a3c-4472-af05-215a5ccd715d', $q$Who founded Kestra?$q$, $q$Kestra was founded in 2021 by Emmanuel Darras and Ludovic Dehon in Paris, France.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4ba1dde9-3a3c-4472-af05-215a5ccd715d', $q$Does Kestra offer a managed cloud version?$q$, $q$Yes, Kestra Cloud is a fully managed, usage-billed SaaS offering with automatic scaling, built-in security and SOC2 compliance.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4ba1dde9-3a3c-4472-af05-215a5ccd715d', $q$What kind of workflows can Kestra orchestrate?$q$, $q$Kestra can orchestrate data pipelines, ETL/ELT jobs, machine learning workflows, business process automation and infrastructure tasks across cloud and on-premises systems.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4ba1dde9-3a3c-4472-af05-215a5ccd715d', $q$How much does Kestra Enterprise Edition cost?$q$, $q$Enterprise Edition pricing is custom and based on organization size and required features; interested customers need to contact Kestra's sales team for a quote.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4ba1dde9-3a3c-4472-af05-215a5ccd715d', $q$Data pipeline orchestration$q$, $q$Teams use Kestra to schedule and monitor ETL/ELT pipelines across warehouses, databases and dbt models with full observability.$q$, $q$Data engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4ba1dde9-3a3c-4472-af05-215a5ccd715d', $q$Event-driven automation$q$, $q$Kestra triggers workflows from webhooks, file arrivals or queue messages, enabling near-real-time business process automation.$q$, $q$Platform and DevOps engineers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4ba1dde9-3a3c-4472-af05-215a5ccd715d', $q$Enterprise-grade AI and ML workflow orchestration$q$, $q$Large organizations run governed, auditable ML and AI pipelines with SSO, RBAC and dedicated worker groups via the Enterprise Edition.$q$, $q$Enterprise IT and MLOps teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4ba1dde9-3a3c-4472-af05-215a5ccd715d', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["1,200+ plugins","Unlimited flows and executions","Event-driven scheduling","Declarative workflows as code and UI-based design","Self-hosted, multi-cloud and air-gapped deployment"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4ba1dde9-3a3c-4472-af05-215a5ccd715d', $q$Kestra Cloud$q$, $q$Usage-based$q$, $q$Pay-as-you-go$q$, NULL, $q$["All Open Source features","Fully managed hosting, upgrades and monitoring","Automatic scaling","Built-in security and governance","SOC2 compliant","Enterprise plugins included"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4ba1dde9-3a3c-4472-af05-215a5ccd715d', $q$Enterprise Edition$q$, $q$Custom pricing$q$, $q$Annual$q$, NULL, $q$["All Cloud features","LDAP, SCIM and custom RBAC","SSO and public cloud authentication","Audit logs and storage isolation","Multi-tenant support","Worker groups and dedicated task runners","AI Copilot with custom models","SLA-backed customer success program"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4ba1dde9-3a3c-4472-af05-215a5ccd715d', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Kestra is an open-source orchestration platform built to unify data, AI and infrastructure workflows under a single declarative, event-driven engine. Founded in 2021 in Paris by Emmanuel Darras and Ludovic Dehon, the company has grown quickly, raising a Series A round in 2026 that brought total funding to roughly 36 million dollars, and now claims tens of thousands of organizations running billions of workflow executions on the platform annually.$q$, $q$Unlike orchestrators that require workflows to be written exclusively in Python, Kestra defines flows in YAML, which can be authored directly as code or built visually through its UI. This declarative model, combined with support for more than 1,200 plugins spanning cloud providers, databases, scripting languages and AI tooling, lets teams orchestrate polyglot pipelines and react to real-time events rather than only running on fixed schedules.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4ba1dde9-3a3c-4472-af05-215a5ccd715d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Kestra's core strength is its combination of declarative-as-code workflow definitions with a UI that stays in sync, so teams can edit flows visually or in YAML without drift between the two. Event-driven triggers let workflows kick off from webhooks, queues, file system events or API calls, in addition to traditional cron scheduling, which suits both batch data pipelines and near-real-time automation.$q$, $q$The plugin ecosystem is one of the platform's biggest differentiators, giving out-of-the-box integrations for major cloud platforms, data warehouses, dbt, Kubernetes, containers and general-purpose scripting so a single pipeline can mix languages and tools rather than forcing everything into one framework. For organizations with stricter requirements, the Enterprise Edition adds SSO, LDAP and SCIM-based access control, audit logging, multi-tenancy, worker groups, external secrets managers, and an AI Copilot for building and debugging flows.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4ba1dde9-3a3c-4472-af05-215a5ccd715d', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Kestra follows a three-tier model. The open-source edition is free and self-hosted, offering unlimited flows and executions with the full plugin catalog, making it a genuine option for teams comfortable managing their own infrastructure. Kestra Cloud is a fully managed SaaS product billed on usage, removing the operational burden of scaling and patching the orchestrator while adding governance and SOC2-compliant security by default.$q$, $q$The Enterprise Edition targets larger organizations that need self-hosted or private-cloud deployment with enterprise-grade access control, compliance and support; pricing is custom and quote-based, scaling with organization size, deployment footprint and the specific enterprise features required. Prospective enterprise customers typically need to contact Kestra's sales team or book a demo to receive a quote, as detailed pricing is not published publicly.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4ba1dde9-3a3c-4472-af05-215a5ccd715d', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
