INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6902e4ce-4e99-4913-bcb5-bbb569db7b67', $q$Multi-language and multi-location support$q$, $q$Localizes keyword data across different countries and languages.$q$, 7);
