INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6902e4ce-4e99-4913-bcb5-bbb569db7b67', $q$Consolidates keyword research, rank tracking, audits and content tools in one product$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6902e4ce-4e99-4913-bcb5-bbb569db7b67', $q$Simple two-tier pricing that is easy to evaluate$q$, 2);
