INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6902e4ce-4e99-4913-bcb5-bbb569db7b67', $q$Less suited to large agencies managing many client accounts$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6902e4ce-4e99-4913-bcb5-bbb569db7b67', $q$How much does Keysearch cost?$q$, $q$Keysearch has two plans: Starter at 24 dollars per month and Pro at 48 dollars per month, with annual billing available at a discount.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6902e4ce-4e99-4913-bcb5-bbb569db7b67', $q$Who founded Keysearch?$q$, $q$Keysearch was founded in 2015 by Dan Pfeffer.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6902e4ce-4e99-4913-bcb5-bbb569db7b67', $q$Is Keysearch a good alternative to Ahrefs or Semrush?$q$, $q$Keysearch offers solid core keyword research and rank tracking at a much lower price, making it popular with bloggers and small businesses, but its backlink data and audit depth do not match Ahrefs or Semrush.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6902e4ce-4e99-4913-bcb5-bbb569db7b67', $q$What is Foresight in Keysearch?$q$, $q$Foresight is Keysearch's AI-powered recommendation engine that guides SEO strategy; it is only available on the Pro plan.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6902e4ce-4e99-4913-bcb5-bbb569db7b67', $q$Does Keysearch offer a free trial?$q$, $q$Yes, Keysearch offers a free trial for new users to test the platform before committing to a paid plan.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6902e4ce-4e99-4913-bcb5-bbb569db7b67', $q$Can Keysearch do YouTube keyword research?$q$, $q$Yes, Keysearch includes a dedicated mode for researching keywords specifically for YouTube video SEO.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6902e4ce-4e99-4913-bcb5-bbb569db7b67', $q$Blog keyword research$q$, $q$Bloggers use Keysearch to find low-competition, high-value keywords to target for organic traffic growth.$q$, $q$Bloggers and content creators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6902e4ce-4e99-4913-bcb5-bbb569db7b67', $q$Affiliate site SEO$q$, $q$Affiliate marketers use Keysearch's difficulty scoring and rank tracking to find winnable niches and monitor progress.$q$, $q$Affiliate marketers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6902e4ce-4e99-4913-bcb5-bbb569db7b67', $q$Small business SEO on a budget$q$, $q$Small businesses use Keysearch's consolidated toolkit for keyword research, audits and rank tracking without enterprise SEO spend.$q$, $q$Small business owners and solo marketers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6902e4ce-4e99-4913-bcb5-bbb569db7b67', $q$Starter$q$, $q$$24/month$q$, $q$Monthly (annual available)$q$, NULL, $q$["200 keyword searches/day","80 tracked keywords/month","2,000 audited pages/month","5,000 AI credits/month","Does not include Foresight AI engine"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6902e4ce-4e99-4913-bcb5-bbb569db7b67', $q$Pro$q$, $q$$48/month$q$, $q$Monthly (annual available)$q$, NULL, $q$["Includes Foresight AI engine","500 keyword searches/day","200 tracked keywords/month","5,000 audited pages/month","15,000 AI credits/month"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6902e4ce-4e99-4913-bcb5-bbb569db7b67', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Keysearch is a budget-oriented SEO keyword research tool founded in 2015 by Dan Pfeffer, built to give bloggers, affiliate marketers and small businesses access to core SEO functionality without the price tag of enterprise suites like Ahrefs or Semrush. The platform consolidates keyword research, competitor analysis, rank tracking and content optimization into a single interface.$q$, $q$Rather than competing on data depth with the largest SEO platforms, Keysearch positions itself around affordability and simplicity, typically priced at a fraction of comparable tools, making it a common recommendation for solo creators and small teams just starting to invest seriously in organic search.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6902e4ce-4e99-4913-bcb5-bbb569db7b67', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Keysearch's keyword research tool surfaces search volume, a proprietary keyword difficulty score, cost-per-click data and related keyword suggestions, with a dedicated mode for YouTube keyword research. Competitor analysis lets users see which keywords a rival domain ranks for, while SERP analysis shows the top-ranking pages for a query along with backlink and on-page signals to gauge realistic difficulty.$q$, $q$Rank tracking monitors keyword position changes over time, the Website Audit tool flags technical SEO issues across a site, and the AI Content Assistant analyzes top-ranking content to suggest related keywords and entities for on-page optimization. The Pro-tier-exclusive Foresight engine adds AI-powered strategic recommendations on top of the core toolset.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6902e4ce-4e99-4913-bcb5-bbb569db7b67', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Keysearch offers two monthly subscription tiers. Starter costs 24 dollars per month with 200 keyword searches per day, 80 tracked keywords, 2,000 audited pages and 5,000 AI credits monthly, without access to Foresight. Pro costs 48 dollars per month and unlocks the Foresight AI recommendation engine along with higher limits across searches, tracked keywords, audited pages and AI credits.$q$, $q$Both plans can be billed annually at a discount equivalent to roughly two free months, and a free trial is available for prospective users to test the platform before subscribing.$q$]::text[], 2);
