INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0ae551c4-e1e4-4011-b3e4-9ec706fc44ff', $q$Schema-first GraphQL API generation$q$, $q$Automatically generates a full GraphQL API from a code-defined data schema, with no hand-written CRUD endpoints.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0ae551c4-e1e4-4011-b3e4-9ec706fc44ff', $q$Auto-generated Admin UI$q$, $q$React-based admin interface that reflects schema fields and access control rules without extra configuration.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0ae551c4-e1e4-4011-b3e4-9ec706fc44ff', $q$Prisma database layer$q$, $q$Built on Prisma for schema migrations with support for PostgreSQL, MySQL and SQLite.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0ae551c4-e1e4-4011-b3e4-9ec706fc44ff', $q$Fine-grained access control$q$, $q$Code-defined permissions at the list, field and operation level for precise authorization rules.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0ae551c4-e1e4-4011-b3e4-9ec706fc44ff', $q$Custom React components$q$, $q$Admin UI can be extended and customized with bespoke React components for unique editorial workflows.$q$, 4);
