INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0ae551c4-e1e4-4011-b3e4-9ec706fc44ff', $q$Event hooks$q$, $q$Run custom logic before or after create, update or delete operations.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0ae551c4-e1e4-4011-b3e4-9ec706fc44ff', $q$TypeScript-first development$q$, $q$Full TypeScript and JavaScript support for type-safe schema and application development.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0ae551c4-e1e4-4011-b3e4-9ec706fc44ff', $q$Completely free, open-source, self-hosted with no licensing fees$q$, 0);
