INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0ae551c4-e1e4-4011-b3e4-9ec706fc44ff', $q$Strong TypeScript support and Prisma-based migrations$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0ae551c4-e1e4-4011-b3e4-9ec706fc44ff', $q$Fine-grained, code-defined access control$q$, 3);
