INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0ae551c4-e1e4-4011-b3e4-9ec706fc44ff', $q$Is KeystoneJS free to use?$q$, $q$Yes, KeystoneJS is fully open-source under the MIT license with no paid tier or licensing fee.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0ae551c4-e1e4-4011-b3e4-9ec706fc44ff', $q$Who created KeystoneJS?$q$, $q$KeystoneJS was created in 2013 by Thinkmill, a Sydney-based design and development consultancy, and continues to be maintained by Thinkmill Labs and the open-source community.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0ae551c4-e1e4-4011-b3e4-9ec706fc44ff', $q$What databases does KeystoneJS support?$q$, $q$Keystone 6 is built on Prisma and supports PostgreSQL, MySQL and SQLite with managed schema migrations.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0ae551c4-e1e4-4011-b3e4-9ec706fc44ff', $q$Does KeystoneJS offer managed hosting?$q$, $q$No, there is no official managed hosting offering from the Keystone project; teams self-host on their own infrastructure.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0ae551c4-e1e4-4011-b3e4-9ec706fc44ff', $q$How does KeystoneJS generate its API?$q$, $q$Keystone auto-generates a full GraphQL API, including pagination, sorting and filtering, directly from a code-defined schema.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0ae551c4-e1e4-4011-b3e4-9ec706fc44ff', $q$What are the main alternatives to KeystoneJS?$q$, $q$Common alternatives include Strapi and Directus, both of which similarly auto-generate CRUD APIs and admin interfaces from a schema, as well as hosted platforms like Contentful and Sanity.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0ae551c4-e1e4-4011-b3e4-9ec706fc44ff', $q$Custom application backends$q$, $q$Development teams use KeystoneJS to build backends for web and mobile applications with a generated GraphQL API.$q$, $q$Full-stack and backend developers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0ae551c4-e1e4-4011-b3e4-9ec706fc44ff', $q$Content-driven websites$q$, $q$Teams build static and dynamic marketing sites and blogs powered by Keystone's content model and admin UI.$q$, $q$Development agencies and in-house web teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0ae551c4-e1e4-4011-b3e4-9ec706fc44ff', $q$Multi-channel content distribution$q$, $q$Organizations use Keystone's GraphQL API to distribute content across web, mobile and other channels from one source.$q$, $q$Enterprises with omnichannel content needs$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0ae551c4-e1e4-4011-b3e4-9ec706fc44ff', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full GraphQL API generation","Auto-generated Admin UI","Prisma-based database migrations","Fine-grained access control","Self-hosted deployment","MIT licensed"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0ae551c4-e1e4-4011-b3e4-9ec706fc44ff', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$KeystoneJS is an open-source headless CMS and application framework for Node.js, originally created in 2013 by Thinkmill, a Sydney-based design and development consultancy whose developers include Jed Watson, Boris Bozic and Joss Mackison. The project remains actively maintained under the MIT license by Thinkmill Labs and its open-source community.$q$, $q$Keystone's defining approach is schema-first development: developers define their data model once, in code, and Keystone auto-generates both a GraphQL API and an admin UI from that schema. The current major version, Keystone 6, is built on Prisma, supporting PostgreSQL, MySQL and SQLite with managed schema migrations, replacing the Express/MongoDB stack used by earlier Keystone versions.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0ae551c4-e1e4-4011-b3e4-9ec706fc44ff', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The auto-generated GraphQL API includes built-in pagination, sorting, filtering and session-aware queries, and can be extended with custom resolvers and mutations for application-specific logic. The React-based Admin UI reflects the defined schema and access control rules automatically, and supports custom React components and a configurable WYSIWYG rich text editor for tailored editorial workflows.$q$, $q$Keystone provides a comprehensive set of field types, fine-grained code-defined access control at the list, field and operation level, session management, and event hooks for running custom logic around data operations, making it a full application backend framework rather than just a content repository.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0ae551c4-e1e4-4011-b3e4-9ec706fc44ff', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$KeystoneJS is entirely free and open-source with no paid tier or licensing fee from the project itself; there is no official managed hosting offering, so teams self-host on their own infrastructure, whether traditional servers, containers, or serverless platforms.$q$, $q$Because there is no vendor subscription, costs are limited to hosting, database and operational effort, distinguishing Keystone's pricing model from commercial hosted headless CMS platforms like Contentful or Sanity, which charge based on usage, seats or API call volume.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0ae551c4-e1e4-4011-b3e4-9ec706fc44ff', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0ae551c4-e1e4-4011-b3e4-9ec706fc44ff', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0ae551c4-e1e4-4011-b3e4-9ec706fc44ff', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
