INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('017afd53-6702-45ee-8be8-f9561ba970a4', $q$AI-powered keyword clustering$q$, $q$Groups thousands of keywords into search-intent clusters using live SERP data rather than simple text similarity.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('017afd53-6702-45ee-8be8-f9561ba970a4', $q$Large-scale keyword upload$q$, $q$Supports uploading and processing up to 50,000 keywords in a single project.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('017afd53-6702-45ee-8be8-f9561ba970a4', $q$AI content briefs$q$, $q$Generates structured content briefs with recommended subtopics and entities for each keyword cluster.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('017afd53-6702-45ee-8be8-f9561ba970a4', $q$AI Writing Agent$q$, $q$Drafts complete articles automatically based on a keyword cluster and brief.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('017afd53-6702-45ee-8be8-f9561ba970a4', $q$Writing assistant$q$, $q$In-line content optimization assistance while drafting articles.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('017afd53-6702-45ee-8be8-f9561ba970a4', $q$Shared workspaces$q$, $q$Multi-seat, multi-workspace collaboration for agencies and content teams.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('017afd53-6702-45ee-8be8-f9561ba970a4', $q$Credit-based usage model$q$, $q$Flexible consumption of clustering, briefs and writing features based on a shared credit pool.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('017afd53-6702-45ee-8be8-f9561ba970a4', $q$Live SERP-based intent grouping$q$, $q$Clusters keywords based on which pages actually rank for them, reflecting real search engine behavior.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('017afd53-6702-45ee-8be8-f9561ba970a4', $q$Clustering accuracy based on live SERP data rather than simple semantic similarity$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('017afd53-6702-45ee-8be8-f9561ba970a4', $q$Handles very large keyword lists (up to 50,000 keywords)$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('017afd53-6702-45ee-8be8-f9561ba970a4', $q$Expanded feature set covers briefs and full article drafting, not just clustering$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('017afd53-6702-45ee-8be8-f9561ba970a4', $q$Low-cost 7-day trial for $1$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('017afd53-6702-45ee-8be8-f9561ba970a4', $q$Team collaboration features on Professional and Enterprise tiers$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('017afd53-6702-45ee-8be8-f9561ba970a4', $q$Credit-based pricing can become expensive with heavy AI Writing Agent usage$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('017afd53-6702-45ee-8be8-f9561ba970a4', $q$Basic plan is limited to a single user seat$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('017afd53-6702-45ee-8be8-f9561ba970a4', $q$Enterprise pricing is not published and requires custom quotes$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('017afd53-6702-45ee-8be8-f9561ba970a4', $q$Focused mainly on clustering/strategy, less on technical SEO or backlinks$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('017afd53-6702-45ee-8be8-f9561ba970a4', $q$AI-generated content still typically requires human editing before publishing$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('017afd53-6702-45ee-8be8-f9561ba970a4', $q$What does Keyword Insights do?$q$, $q$Keyword Insights is an AI-powered platform that clusters large keyword lists into search-intent-based groups using live SERP data, and also generates content briefs and AI-drafted articles.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('017afd53-6702-45ee-8be8-f9561ba970a4', $q$How much does Keyword Insights cost?$q$, $q$Plans start at 58 dollars per month for Basic (10,000 credits), with Professional at 99 dollars per month (20,000 credits) and custom Enterprise pricing for larger teams.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('017afd53-6702-45ee-8be8-f9561ba970a4', $q$Who founded Keyword Insights?$q$, $q$Keyword Insights was founded in 2021 by Andreas Voniatis and Suganthan Mohanadasan, operating under Snippet Digital Ltd.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('017afd53-6702-45ee-8be8-f9561ba970a4', $q$How does Keyword Insights clustering work?$q$, $q$It runs live SERP analysis on each uploaded keyword and uses AI to group keywords that share the same ranking pages and search intent.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('017afd53-6702-45ee-8be8-f9561ba970a4', $q$How many keywords can I upload to Keyword Insights?$q$, $q$Users can upload and process up to 50,000 keywords in a single clustering project.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('017afd53-6702-45ee-8be8-f9561ba970a4', $q$What are alternatives to Keyword Insights?$q$, $q$Common alternatives include Surfer SEO and Clearscope, both of which focus more on scoring and optimizing individual content pieces rather than upstream keyword clustering.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('017afd53-6702-45ee-8be8-f9561ba970a4', $q$Large-scale content planning$q$, $q$SEO agencies use Keyword Insights to cluster tens of thousands of keywords into a structured content calendar based on real search intent.$q$, $q$SEO agencies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('017afd53-6702-45ee-8be8-f9561ba970a4', $q$Topical authority building$q$, $q$In-house content teams use intent-based clusters to plan comprehensive topic coverage that builds topical authority.$q$, $q$In-house content marketing teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('017afd53-6702-45ee-8be8-f9561ba970a4', $q$AI-assisted content production$q$, $q$Content strategists use the AI Writing Agent and briefs to accelerate first-draft article production from keyword research.$q$, $q$Content strategists and writers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('017afd53-6702-45ee-8be8-f9561ba970a4', $q$Basic$q$, $q$$58/month$q$, $q$Monthly (annual discount available)$q$, NULL, $q$["10,000 credits/month","1 user seat","5 workspaces","AI agent support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('017afd53-6702-45ee-8be8-f9561ba970a4', $q$Professional$q$, $q$$99/month$q$, $q$Monthly (annual discount available)$q$, NULL, $q$["20,000 credits/month","3 user seats","10 workspaces","Team sharing"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('017afd53-6702-45ee-8be8-f9561ba970a4', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Contact sales$q$, NULL, $q$["Custom credit allocation","Custom user seats","Custom workspaces","Priority support and onboarding"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('017afd53-6702-45ee-8be8-f9561ba970a4', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Keyword Insights is an AI-powered keyword clustering and content strategy platform founded in 2021 by SEO industry figures Andreas Voniatis and Suganthan Mohanadasan, operating under the legal entity Snippet Digital Ltd. The platform automates the process of grouping large keyword lists into search-intent-based clusters using live SERP data.$q$, $q$Users can upload up to 50,000 keywords at once, and the platform's AI clustering algorithm groups keywords that share the same ranking pages and intent signals, rather than relying only on lexical or semantic similarity. Since launch, the product has expanded beyond pure clustering into a broader content workflow, adding AI content briefs, a writing assistant, and a full AI Writing Agent.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('017afd53-6702-45ee-8be8-f9561ba970a4', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The core clustering engine analyzes live SERP data for each uploaded keyword and groups terms that share ranking pages, producing intent-based clusters that reflect actual search engine behavior. On top of clustering, the platform generates AI content briefs outlining recommended structure and subtopics for each cluster, and offers a writing assistant for in-line optimization plus a full AI Writing Agent capable of drafting complete articles.$q$, $q$The platform supports team collaboration through shared workspaces and multi-seat plans on its higher tiers, making it suited to agencies and larger in-house content teams that need to coordinate large-scale content planning across multiple stakeholders.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('017afd53-6702-45ee-8be8-f9561ba970a4', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Keyword Insights uses a credit-based subscription model. The Basic plan costs 58 dollars per month for 10,000 credits, 1 seat and 5 workspaces; the Professional plan costs 99 dollars per month for 20,000 credits, 3 seats and 10 workspaces with team sharing; and Enterprise offers custom credits, seats and workspaces with priority support at custom pricing.$q$, $q$Credits are consumed per action: 1 credit per keyword clustered, 100 credits per content brief, 200 credits per writing-assistant article, and 1,200 credits per AI Writing Agent article. A 7-day trial is available for 1 dollar with 5,000 one-time credits, auto-converting to pay-as-you-go if not upgraded.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('017afd53-6702-45ee-8be8-f9561ba970a4', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('017afd53-6702-45ee-8be8-f9561ba970a4', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('017afd53-6702-45ee-8be8-f9561ba970a4', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
