INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', $q$Free courses across subjects$q$, $q$Over 7,000 lessons spanning preK-2 through college-level math, science, literacy and financial literacy.$q$, 0);
