INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', $q$Video-based instruction$q$, $q$Short instructional videos paired with practice exercises and quizzes.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', $q$Progress tracking and analytics$q$, $q$Tools for students, parents and teachers to monitor learning progress.$q$, 6);
