INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', $q$Extremely broad subject coverage from preK through college level$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', $q$Mastery-based, self-paced learning model$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', $q$Growing AI tutor (Khanmigo) for personalized support$q$, 3);
