INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', $q$Depth in advanced/specialized subjects can trail dedicated paid platforms$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', $q$Khanmigo adoption has reportedly been uneven among students with access$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', $q$Relies on donations, which can create funding uncertainty over time$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', $q$Less structured credentialing compared to platforms offering certificates/degrees$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', $q$Primarily English-first content, though some subjects are localized$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', $q$Is Khan Academy free?$q$, $q$Yes, Khan Academy's core educational content is entirely free for all users, funded through donations and grants as a nonprofit organization.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', $q$Who founded Khan Academy?$q$, $q$Khan Academy was founded by Sal Khan, who began tutoring relatives online in 2004 and formally incorporated the organization as a nonprofit in 2008.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', $q$What is Khanmigo?$q$, $q$Khanmigo is Khan Academy's AI-powered tutor that provides personalized, Socratic-style tutoring for students and planning/grading assistance for teachers.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', $q$What subjects does Khan Academy cover?$q$, $q$Khan Academy covers preK-2 literacy and math, grades 3 through college-level math and science, financial literacy, and standardized test prep including SAT courses.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', $q$How many users does Khan Academy have?$q$, $q$Khan Academy reported 189.6 million total registered users and 62.4 million international learners, educators and parents reached in the SY24-25 school year.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', $q$How is Khan Academy funded?$q$, $q$Khan Academy is funded primarily through philanthropic donations and grants from foundations and individuals, including early support from Google and the Bill and Melinda Gates Foundation.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', $q$Supplemental K-12 learning$q$, $q$Students use Khan Academy to reinforce classroom learning in math and science at their own pace outside school hours.$q$, $q$K-12 students$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', $q$Classroom integration$q$, $q$Teachers and school districts integrate Khan Academy content and Khanmigo into formal curricula for personalized instruction.$q$, $q$Teachers and school districts$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', $q$Standardized test preparation$q$, $q$Students use Khan Academy's free SAT prep courses to study for college entrance exams without paying for tutoring.$q$, $q$High school students preparing for SAT$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', $q$Khan Academy (All Access)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["7,000+ lessons across all subjects","Mastery-based practice and tracking","Khanmigo AI tutor access","SAT and test prep courses","Available to individuals, teachers and schools"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Khan Academy is a nonprofit online education platform founded by Sal Khan, with origins tracing back to 2004 when he began tutoring a cousin remotely using online tools, and formally incorporated as a 501(c)(3) nonprofit in 2008 after Khan left his hedge fund job to pursue it full time. Headquartered in Mountain View, California, the organization is funded through philanthropic donations and major grants rather than user fees, keeping its educational content free for everyone.$q$, $q$Early funding from Google and the Bill and Melinda Gates Foundation in 2010 allowed Khan Academy to grow from a one-person video library into a full nonprofit organization. It now reaches tens of millions of learners globally each year, delivering thousands of lessons across math, science, literacy and test preparation.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Khan Academy's platform offers more than 7,000 lessons and 400+ supplementary books spanning preK-2 literacy and math, grades 3 through college-level math and science, financial literacy, and standardized test prep including SAT courses. Content is delivered through short instructional videos combined with practice exercises and mastery-based progress tracking that adapts to each learner's pace.$q$, $q$Its newest major feature is Khanmigo, an AI-powered tutor built on large language model technology that provides Socratic-style personalized tutoring for students and lesson-planning/grading support for teachers. Khanmigo usage grew roughly seventeenfold between the 2024-25 and 2025-26 school years, reflecting rapid adoption as Khan Academy integrates AI more deeply into its offering.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Khan Academy's core educational content is entirely free to use for all learners, teachers and parents, reflecting its nonprofit mission and funding model based on donations and grants rather than subscriptions or course fees.$q$, $q$The organization sustains itself through philanthropic support from major donors and foundations, along with district partnerships for institutional adoption, rather than by charging end users, which distinguishes it from for-profit online education platforms that rely on paid subscriptions.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
