INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('78732199-bee3-492f-a014-b27c713b3691', $q$Semantic document search$q$, $q$Indexes personal documents (PDFs, images, Markdown, Word, Notion) into embeddings for natural-language search and chat.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('78732199-bee3-492f-a014-b27c713b3691', $q$Custom AI agents$q$, $q$Build agents with their own persona, knowledge base, chat model and tool access for specific tasks or roles.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('78732199-bee3-492f-a014-b27c713b3691', $q$Model-agnostic LLM support$q$, $q$Runs against local open models (Llama, Qwen, Mistral) or hosted commercial models (GPT, Claude, Gemini).$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('78732199-bee3-492f-a014-b27c713b3691', $q$Scheduled research automation$q$, $q$Automates recurring research tasks and delivers smart notifications.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('78732199-bee3-492f-a014-b27c713b3691', $q$Multi-platform access$q$, $q$Available via browser, desktop app, mobile, and native Obsidian and Emacs integrations.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('78732199-bee3-492f-a014-b27c713b3691', $q$WhatsApp integration$q$, $q$Chat with Khoj directly through WhatsApp for on-the-go access.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('78732199-bee3-492f-a014-b27c713b3691', $q$Image generation and text-to-speech$q$, $q$Generates images and provides spoken playback of AI responses.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('78732199-bee3-492f-a014-b27c713b3691', $q$Self-hostable and open-source$q$, $q$Fully self-hostable under AGPL-3.0, giving users full control over their data and infrastructure.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('78732199-bee3-492f-a014-b27c713b3691', $q$Fully open-source and self-hostable for complete data control$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('78732199-bee3-492f-a014-b27c713b3691', $q$Model-agnostic, supporting both local and commercial LLMs$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('78732199-bee3-492f-a014-b27c713b3691', $q$Wide platform reach, including Obsidian, Emacs and WhatsApp integrations$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('78732199-bee3-492f-a014-b27c713b3691', $q$Free to self-host aside from hardware/infrastructure costs$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('78732199-bee3-492f-a014-b27c713b3691', $q$Backed by Y Combinator with an active open-source community$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('78732199-bee3-492f-a014-b27c713b3691', $q$Official hosted cloud service has been deprecated/shut down$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('78732199-bee3-492f-a014-b27c713b3691', $q$Self-hosting requires technical setup and infrastructure management$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('78732199-bee3-492f-a014-b27c713b3691', $q$Small team (reportedly around 3 employees) limits support resources$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('78732199-bee3-492f-a014-b27c713b3691', $q$Retrieval accuracy can trail more polished closed products like NotebookLM$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('78732199-bee3-492f-a014-b27c713b3691', $q$Documentation and setup complexity may deter non-technical users$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('78732199-bee3-492f-a014-b27c713b3691', $q$Is Khoj free to use?$q$, $q$Yes, the self-hosted version of Khoj is free and open-source, aside from the user's own hardware or hosting costs. The official hosted cloud service has since been deprecated.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('78732199-bee3-492f-a014-b27c713b3691', $q$Who created Khoj?$q$, $q$Khoj was founded by Debanjum Singh and Saba Imran, and is backed by Y Combinator.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('78732199-bee3-492f-a014-b27c713b3691', $q$What file types can Khoj search?$q$, $q$Khoj can index and search images, PDFs, Markdown, Org-mode files, Word documents and Notion exports, alongside general web search.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('78732199-bee3-492f-a014-b27c713b3691', $q$Can Khoj run with local AI models?$q$, $q$Yes, Khoj supports both local open models such as Llama 3, Qwen, Gemma and Mistral, and hosted commercial models like GPT, Claude and Gemini.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('78732199-bee3-492f-a014-b27c713b3691', $q$What platforms does Khoj support?$q$, $q$Khoj is accessible via web browser, desktop app, mobile, and has native integrations with Obsidian, Emacs and WhatsApp.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('78732199-bee3-492f-a014-b27c713b3691', $q$How does Khoj compare to Google's NotebookLM?$q$, $q$Khoj offers similar retrieval-augmented-generation functionality over personal documents, but unlike NotebookLM it is open-source, self-hostable and model-agnostic rather than a closed, hosted-only Google product.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('78732199-bee3-492f-a014-b27c713b3691', $q$Personal knowledge management$q$, $q$Individuals use Khoj to search and chat with their own notes, documents and research across multiple file formats.$q$, $q$Researchers, writers and knowledge workers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('78732199-bee3-492f-a014-b27c713b3691', $q$Privacy-focused AI assistance$q$, $q$Privacy-conscious users self-host Khoj with local LLMs to keep documents and queries entirely off third-party servers.$q$, $q$Privacy-conscious individuals and organizations$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('78732199-bee3-492f-a014-b27c713b3691', $q$Automated research workflows$q$, $q$Users schedule recurring research tasks and custom agents to monitor topics and summarize findings automatically.$q$, $q$Analysts and independent researchers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('78732199-bee3-492f-a014-b27c713b3691', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full feature set","Local or hosted LLM support","Obsidian, Emacs and WhatsApp integrations","Self-hosted, AGPL-3.0 licensed"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('78732199-bee3-492f-a014-b27c713b3691', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Khoj is an open-source, self-hostable personal AI application founded by Debanjum Singh and Saba Imran, backed by Y Combinator, and built as an 'AI second brain' that lets users search and chat with their own notes and documents alongside the open web. The project is distributed under the AGPL-3.0 license and has attracted a large open-source community, with tens of thousands of GitHub stars.$q$, $q$Functionally similar in concept to Google's NotebookLM, Khoj indexes personal documents into semantic embeddings and answers natural-language questions grounded in the user's own files, while additionally supporting custom AI agents, scheduled research automations, image generation and text-to-speech, all of which can run against either local open models or hosted commercial LLMs.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('78732199-bee3-492f-a014-b27c713b3691', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Khoj indexes a wide range of document types, including images, PDFs, Markdown, Org-mode, Word documents and Notion exports, and lets users query them conversationally through semantic search. Users can build custom agents with distinct personas, knowledge bases, chat models and tool access, and schedule automated research tasks with smart notifications.$q$, $q$The platform is model-agnostic, supporting both local on-device models (Llama 3, Qwen, Gemma, Mistral, DeepSeek) and hosted commercial models (GPT, Claude, Gemini), giving users control over privacy and cost trade-offs. Khoj is accessible via browser, desktop app, mobile, and native integrations for Obsidian, Emacs, and WhatsApp.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('78732199-bee3-492f-a014-b27c713b3691', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Khoj's self-hosted version is free and open-source, aside from the user's own hardware or hosting costs, reflecting its privacy-first, community-driven design. The project's official hosted cloud service, previously offered at app.khoj.dev with a free trial and paid plans including student discounts, has since been deprecated.$q$, $q$Users who want a cloud-hosted deployment today typically self-host on third-party infrastructure such as Railway, rather than through an officially maintained Khoj-run cloud service, since the company no longer offers its own hosted subscription.$q$]::text[], 2);
