-- в”Ђв”Ђ Khan Academy в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$Free nonprofit online education platform offering thousands of lessons, courses and an AI tutor covering math, science and more from preK through college.$q$, short_description),
  pricing_model = COALESCE($q$Free$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2008, founded_year),
  company_size = COALESCE($q$201-500 employees$q$, company_size),
  headquarters = COALESCE($q$Mountain View, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Spanish$q$, $q$and dozens of other languages via international partners$q$]::text[],
  seo_title = COALESCE($q$Khan Academy Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Khan Academy review covering free courses, subjects, the Khanmigo AI tutor, funding model, and how it compares to Coursera and Duolingo.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Khan Academy is an American nonprofit educational organization headquartered in Mountain View, California, founded by Salman 'Sal' Khan. Its origins trace back to 2004, when Khan began remotely tutoring a cousin in math using online tools, which grew into a library of instructional videos he shared for free; he continued building the project in his spare time while working at a hedge fund until 2009, when he left that job to work on it full-time, funded initially by his own savings and then by an early donation from philanthropist Ann Doerr. Khan Academy was formally incorporated as a 501(c)(3) nonprofit organization in 2008. It gained major early momentum in September 2010 when it received large grants from Google (2 million dollars) and the Bill and Melinda Gates Foundation (1.5 million dollars), which allowed Khan to build out a full organization beyond himself. Since then, the organization has been sustained primarily through philanthropic donations rather than tuition or subscription revenue, with supporters over the years including the Gates Foundation, Google, Bank of America, the Amgen Foundation, Ann and John Doerr, the Musk Foundation, Stand Together Trust, Reed Hastings, the Overdeck Family Foundation, and others, keeping its core educational content free for all users. Khan Academy's platform delivers instructional content across preK-2 literacy and math, grades 3 through college-level math and science, financial literacy, and standardized test preparation (including SAT prep), organized into more than 7,000 lessons and over 400 supplementary books/resources, taught through short instructional videos paired with practice exercises, quizzes and mastery-based progress tracking that adapts to each learner's pace. In its most recent reported school year (SY24-25), Khan Academy reported reaching 62.4 million international learners, educators and parents, alongside 54.2 million 'grassroots' users outside of formal international district partnerships, and 189.6 million total registered users, logging 66.8 billion cumulative learning minutes on the platform. The organization also partners directly with school districts internationally to integrate its content into formal curricula, and continually expands its course catalog, releasing 24 new or expanded courses in SY24-25 alone, including a Middle School Chemistry course, SAT prep courses, and a Constitution 101 course. A major recent product expansion is Khanmigo, Khan Academy's AI-powered tutor and teaching assistant, which uses large language model technology to provide personalized, Socratic-style tutoring to students and lesson-planning and grading assistance to teachers rather than simply giving away answers. Khanmigo usage grew dramatically between the 2024-25 and 2025-26 school years, from roughly 40,000 users to about 700,000 users, more than a seventeenfold increase, although some reporting has noted that only a fraction of students with access to Khanmigo actively use it, prompting Khan Academy to redesign aspects of the tool. Because Khan Academy is a nonprofit funded by donations and grants rather than a commercial company charging subscription fees, its core content and courses remain free to all users, which sharply differentiates its business and access model from for-profit education competitors such as Coursera, Udemy, and Duolingo, which rely on paid subscriptions, course fees, or freemium upsells for revenue; Khan Academy instead monetizes indirectly through philanthropic funding and district partnerships while keeping the end-user experience free. Its differentiation from these competitors is therefore less about product depth in any single subject and more about being a universally free, broad-curriculum, K-12-and-beyond learning platform trusted by schools, backed by major philanthropic institutions, and increasingly augmented by AI tutoring through Khanmigo, positioning it as core infrastructure for supplemental and remedial education worldwide rather than a paid consumer education product.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '3272c3b2-7b50-4f01-838c-a33fa1daae36';

